/// Suspend the current 'Running' task and run the next task in task list.
pub fn suspend_current_and_run_next() {
    // There must be an application running.
    let task = take_current_task().unwrap();

    // ---- access current TCB exclusively
    let mut task_inner = task.inner_exclusive_access();
    let task_cx_ptr = &mut task_inner.task_cx as *mut KContext;
    // Change status to Ready
    task_inner.task_status = TaskStatus::Ready;
    drop(task_inner);
    // ---- release current PCB

    // push back to ready queue.
    add_task(task);
    // jump to scheduling cycle
    schedule(task_cx_ptr);
}

/// pid of usertests app in make run TEST=1
pub const IDLE_PID: usize = 0;

/// Exit the current 'Running' task and run the next task in task list.
pub fn exit_current_and_run_next(exit_code: i32) -> ! {
    // take from Processor
    let task = take_current_task().unwrap();

    let pid = task.getpid();
    if pid == IDLE_PID {
        info!(
            "[exit_current_and_run_next] Idle process exit with exit_code {} ...",
            exit_code
        );
        shutdown();
    }

    // remove from pid2task
    remove_from_pid2task(task.getpid());
    let exiting_init = Arc::ptr_eq(&task, &INITPROC);
    // **** access current TCB exclusively
    let (
        should_recycle_memory,
        should_clear_fd_table,
        clear_child_tid,
        memory_set,
        fd_table,
        orphaned_children,
        parent,
    ) = {
        let mut inner = task.inner_exclusive_access();
        inner.task_status = TaskStatus::Zombie;
        if !inner.killed {
            inner.exit_code = exit_code;
        }
        let orphaned_children = core::mem::take(&mut inner.children);
        let parent = inner.parent.clone();
        (
            Arc::strong_count(&inner.memory_set) == 1,
            Arc::strong_count(&inner.fd_table) == 1,
            inner.clear_child_tid,
            inner.memory_set.clone(),
            inner.fd_table.clone(),
            orphaned_children,
            parent,
        )
    };
    if let Some(parent) = parent.and_then(|parent| parent.upgrade()) {
        parent.inner_exclusive_access().signals |= SignalFlags::SIGCHLD;
    }
    if let Some(clear_child_tid) = clear_child_tid {
        let clear_tid_vaddr = VirtAddr::new(clear_child_tid).floor();
        let clear_tid_ready = memory_set
            .translate(clear_tid_vaddr)
            .map(|(_, flags)| flags.contains(MappingFlags::W))
            .unwrap_or(false)
            || memory_set.lazy_page_fault(clear_tid_vaddr, StorePageFault(clear_child_tid))
            || memory_set.cow_page_fault(clear_tid_vaddr, StorePageFault(clear_child_tid));
        if clear_tid_ready {
            put_data(memory_set.token(), clear_child_tid as *mut u32, 0u32);
        } else {
            warn!(
                "[task_exit_clear_child_tid] pid={} skip unmapped clear_child_tid={:#x}",
                pid, clear_child_tid
            );
        }
    }
    // **** release current PCB

    // Reparent after releasing the exiting task's TCB to avoid borrowing INITPROC
    // while the current task is INITPROC or while a child aliases INITPROC.
    if !exiting_init {
        let mut initproc_inner = INITPROC.inner_exclusive_access();
        for child in orphaned_children {
            if Arc::ptr_eq(&child, &task) || Arc::ptr_eq(&child, &INITPROC) {
                continue;
            }
            let mut child_inner = child.inner_exclusive_access();
            child_inner.parent = Some(Arc::downgrade(&INITPROC));
            child_inner.adopted_by_init = true;
            drop(child_inner);
            initproc_inner.children.push(child);
        }
    }
    if should_recycle_memory {
        memory_set.recycle_data_pages();
    }
    if should_clear_fd_table {
        fd_table.clear();
    }
    drop(memory_set);
    drop(fd_table);
    // drop task manually to maintain rc correctly
    drop(task);
    // we do not have to save task context
    let mut unused = KContext::blank();
    loop {
        schedule(&mut unused as *mut _);
    }
}

pub fn exit_current_group_and_run_next(exit_code: i32) -> ! {
    let current = current_task().unwrap();
    let current_pid = current.getpid();
    let (current_memory_set, current_sig_table) = {
        let inner = current.inner_exclusive_access();
        (inner.memory_set.clone(), inner.sig_table.clone())
    };
    drop(current);

    for (_, task) in get_all_tasks() {
        if task.getpid() == current_pid {
            continue;
        }
        let mut inner = task.inner_exclusive_access();
        let same_thread_group = Arc::ptr_eq(&inner.memory_set, &current_memory_set)
            || Arc::ptr_eq(&inner.sig_table, &current_sig_table);
        if same_thread_group && !inner.is_zombie() {
            inner.killed = true;
            inner.exit_code = exit_code;
            inner.exit_core_dumped = false;
            inner.frozen = false;
            inner.signal_mask.remove(SignalFlags::SIGKILL);
            inner.signals |= SignalFlags::SIGKILL;
        }
    }

    drop(current_memory_set);
    drop(current_sig_table);
    exit_current_and_run_next(exit_code)
}

