fn write_u32_to_memory_set(memory_set: &MemorySet, addr: usize, value: u32) -> bool {
    let page = VirtAddr::new(addr).floor();
    let writable = memory_set
        .translate(page)
        .map(|(_, flags)| flags.contains(pagetable::MappingFlags::W))
        .unwrap_or(false)
        || memory_set.lazy_page_fault(page, TrapType::StorePageFault(addr))
        || memory_set.cow_page_fault(page, TrapType::StorePageFault(addr));
    if !writable {
        return false;
    }

    let bytes = value.to_ne_bytes();
    for (idx, byte) in bytes.iter().enumerate() {
        let Some((byte_paddr, _)) = memory_set.translate(VirtAddr::new(addr + idx)) else {
            return false;
        };
        unsafe {
            *byte_paddr.get_mut_ptr::<u8>() = *byte;
        }
    }
    true
}

