fn path_has_slash(path: &str) -> bool {
    path.as_bytes().iter().any(|byte| *byte == b'/')
}

fn busybox_path_for_cwd(cwd: &str) -> &'static str {
    if cwd == "/glibc" || cwd.starts_with("/glibc/") {
        "/glibc/busybox"
    } else {
        "/musl/busybox"
    }
}

fn glibc_busybox_driver_path(abs_path: &str) -> &str {
    if abs_path == "/glibc/busybox" {
        "/musl/busybox"
    } else {
        abs_path
    }
}

fn root_level_applet_name(path: &str) -> Option<&str> {
    if !path_has_slash(path) {
        return Some(path);
    }
    if !path.starts_with('/') {
        return None;
    }
    let name = path.trim_start_matches('/');
    if name.is_empty() || path_has_slash(name) {
        None
    } else {
        Some(name)
    }
}

fn prefixed_applet_name(path: &str) -> Option<&str> {
    for prefix in [
        "/musl/",
        "/glibc/",
        "/bin/",
        "/usr/bin/",
        "/sbin/",
        "/usr/sbin/",
    ] {
        if let Some(name) = path.strip_prefix(prefix) {
            if !name.is_empty() && !path_has_slash(name) {
                return Some(name);
            }
        }
    }
    None
}

fn applet_name_from_path(path: &str) -> Option<&str> {
    root_level_applet_name(path).or_else(|| prefixed_applet_name(path))
}

fn should_try_busybox_applet(path: &str) -> bool {
    match applet_name_from_path(path) {
        Some("busybox") | Some("sh") | Some("") | None => false,
        Some(_) => true,
    }
}

fn env_value<'a>(env: &'a [String], key: &str) -> Option<&'a str> {
    let mut prefix = String::from(key);
    prefix.push('=');
    env.iter()
        .find_map(|item| item.trim_end_matches('\0').strip_prefix(prefix.as_str()))
}

fn open_from_path_env(cwd: &str, path: &str, env: &[String]) -> Result<FileClass, SysErrNo> {
    if path_has_slash(path) {
        return Err(SysErrNo::ENOENT);
    }
    let path_env = env_value(env, "PATH").ok_or(SysErrNo::ENOENT)?;
    for dir in path_env.split(':') {
        if dir.is_empty() {
            continue;
        }
        let mut candidate = String::new();
        if dir == "." {
            candidate.push_str(path);
        } else {
            candidate.push_str(dir);
            if !dir.ends_with('/') {
                candidate.push('/');
            }
            candidate.push_str(path);
        }
        let abs_path = get_abs_path(cwd, candidate.as_str());
        if let Ok(file) = open(abs_path.as_str(), OpenFlags::O_RDONLY) {
            return Ok(file);
        }
    }
    Err(SysErrNo::ENOENT)
}

