fn shebang_line(data: &[u8]) -> Option<&[u8]> {
    if data.len() < 2 || data[0] != b'#' || data[1] != b'!' {
        return None;
    }
    let end = data.iter().position(|b| *b == b'\n').unwrap_or(data.len());
    Some(&data[2..end])
}

/// Parse the bytes after `#!` into (interpreter, optional single arg).
fn parse_shebang(line: &[u8]) -> Option<(&str, Option<&str>)> {
    let text = core::str::from_utf8(line)
        .ok()?
        .trim_end_matches('\r')
        .trim();
    if text.is_empty() {
        return None;
    }
    let mut parts = text.splitn(2, char::is_whitespace);
    let interp = parts.next()?;
    let arg = parts.next().map(str::trim).filter(|a| !a.is_empty());
    Some((interp, arg))
}

fn is_shell_interpreter(interp: &str) -> bool {
    matches!(
        interp,
        "/bin/sh" | "/usr/bin/sh" | "sh" | "/bin/bash" | "/usr/bin/bash" | "bash"
    )
