fn path_has_slash(path: &str) -> bool {
    path.as_bytes().iter().any(|byte| *byte == b'/')
}

fn root_level_applet_name(path: &str) -> Option<&str> {
    if !path_has_slash(path) {
        return Some(path);
    }
    if !path.starts_with('/') {
        return None;
    }
    let name = path.trim_start_matches('/');
    if name.is_empty() || path_has_slash(name) {
        None
    } else {
        Some(name)
    }
}

fn prefixed_applet_name(path: &str) -> Option<&str> {
    for prefix in [
        "/musl/",
        "/glibc/",
        "/bin/",
        "/usr/bin/",
        "/sbin/",
        "/usr/sbin/",
    ] {
        if let Some(name) = path.strip_prefix(prefix) {
            if !name.is_empty() && !path_has_slash(name) {
                return Some(name);
            }
        }
    }
    None
}

fn applet_name_from_path(path: &str) -> Option<&str> {
    root_level_applet_name(path).or_else(|| prefixed_applet_name(path))
}

fn should_try_busybox_applet_path(path: &str) -> bool {
    match applet_name_from_path(path) {
        Some("busybox") | Some("sh") | Some("") | None => false,
        Some(_) => true,
    }
}

fn busybox_path_for_cwd(cwd: &str) -> &'static str {
    if cwd == "/glibc" || cwd.starts_with("/glibc/") {
        "/glibc/busybox"
    } else {
        "/musl/busybox"
    }
}

fn busybox_applet_abs_path(cwd: &str, abs_path: &str) -> Option<&'static str> {
    if should_try_busybox_applet_path(abs_path) {
        Some(busybox_path_for_cwd(cwd))
    } else {
        None
    }
}

fn busybox_applet_probe_path(cwd: &str, path: &str, abs_path: &str) -> Option<&'static str> {
    if should_try_busybox_applet_path(path) {
        Some(busybox_path_for_cwd(cwd))
    } else if should_try_busybox_applet_path(abs_path) {
        busybox_applet_abs_path(cwd, abs_path)
    } else {
        None
    }
}

fn can_ltp_fallback_open(flags: OpenFlags) -> bool {
    (flags & OpenFlags::O_ACCMODE) == OpenFlags::O_RDONLY
        && !flags.contains(OpenFlags::O_CREATE)
        && !flags.contains(OpenFlags::O_TRUNC)
        && !flags.contains(OpenFlags::O_APPEND)
        && !flags.contains(OpenFlags::O_TMPFILE)
        && !flags.contains(OpenFlags::O_DIRECTORY)
        && !flags.contains(OpenFlags::O_PATH)
}

pub fn sys_getcwd(buf: *mut u8, len: usize) -> SyscallRet {
    trace!(
        "[sys_getcwd] called with buf=0x{:x} (output pointer for cwd string), len={}",
        buf as usize,
        len
    );
    let token = current_user_token();
    let task = current_task().unwrap();
    let inner = task.inner_exclusive_access();

    // 获取当前工作目录
    let cwd = inner.fsinfo.get_cwd();
    drop(inner);
    drop(task);
    debug!("[sys_getcwd] current working directory: {}", cwd);

    // 检查缓冲区长度是否足够
    if cwd.len() + 1 > len {
        warn!(
            "[sys_getcwd] buffer too small: need {}, got {}",
            cwd.len() + 1,
            len
        );
        return Err(SysErrNo::ERANGE); // 缓冲区不足
    }

    let mut user_buf = UserBuffer::new(translated_byte_buffer(&token, buf, len));

    let mut cwd_bytes = cwd.as_bytes().to_vec();
    cwd_bytes.push(0);
    user_buf.write(cwd_bytes.as_slice());

    Ok(cwd.len() + 1) // 返回写入的字节数（包括 '\0'）
}

pub fn sys_dup(fd: usize) -> SyscallRet {
    trace!("[sys_dup] called with fd={}", fd);
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return Err(SysErrNo::EBADF);
    }
    let file = inner.fd_table.get_file(fd).ok_or(SysErrNo::EBADF)?;
    let new_fd = inner.alloc_fd();
    if new_fd == usize::MAX {
        return Err(SysErrNo::EMFILE);
    }
    inner.fd_table.set(new_fd, file);
    Ok(new_fd)
}

pub fn sys_dup3(old_fd: usize, new_fd: usize, flags: u32) -> SyscallRet {
    let flags = OpenFlags::from_bits(flags).unwrap();
    trace!(
        "[sys_dup3] called with old_fd={}, new_fd={}, flags={:?}",
        old_fd,
        new_fd,
        flags
    );
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    if old_fd >= inner.fd_table.len() {
        return Err(SysErrNo::EBADF);
    }
    let mut file = inner.fd_table.get_file(old_fd).ok_or(SysErrNo::EBADF)?;
    if old_fd == new_fd {
        debug!("[sys_dup3] old_fd and new_fd are the same");
        return Ok(new_fd);
    }
    if new_fd >= inner.fd_table.len() {
        inner.fd_table.resize(new_fd + 1);
    }
    // 如果 new_fd 已经被占用，先关闭它
    if inner.fd_table.get_file(new_fd).is_some() {
        debug!("[sys_dup3] closing existing new_fd {}", new_fd);
        inner.fd_table.remove(new_fd);
    }
    file.set_flags(flags);
    inner.fd_table.set(new_fd, file);
    Ok(new_fd)
}

pub fn sys_fcntl(fd: usize, cmd: usize, arg: usize) -> SyscallRet {
    trace!(
        "[sys_fcntl] called with fd={}, cmd={:?}({}), arg={}",
        fd,
        fcntl_cmd_name(cmd),
        cmd,
        arg
    );
    let task = current_task().unwrap();
    let mut inner = task.inner_exclusive_access();
    if fd >= inner.fd_table.len() {
        return Err(SysErrNo::EBADF);
    }
    let mut file = inner.fd_table.get_file(fd).ok_or(SysErrNo::EBADF)?;
    match cmd {
        F_DUPFD => {
            let new_fd = inner.fd_table.alloc_fd_larger(arg)?;
            file.unset_cloexec();
            inner.fd_table.set(new_fd, file);
            // task_inner.fs_info.insert_with_glue(fd, fd_new);
            Ok(new_fd)
        }
        F_DUPFD_CLOEXEC => {
            let new_fd = inner.fd_table.alloc_fd_larger(arg)?;
            file.set_cloexec();
            inner.fd_table.set(new_fd, file);
            // task_inner.fs_info.insert_with_glue(fd, fd_new);
            Ok(new_fd)
        }
        F_GETFD => Ok(if file.cloexec() { 1 } else { 0 }),
        F_SETFD => {
            if arg & 1 != 0 {
                file.set_cloexec();
            } else {
                file.unset_cloexec();
            }
            inner.fd_table.set(fd, file);
            Ok(0)
        }
        F_GETFL => Ok(file.get_flags().bits() as usize),
        _ => Err(SysErrNo::EINVAL),
    }
}

