/// 错误类型（静态错误信息，无动态分配）
#[derive(Debug, PartialEq)]
pub enum CloneFlagError {
    MissingRequiredFlags,
    ConflictWithNewNamespace,
}

impl fmt::Display for CloneFlagError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        match self {
            Self::MissingRequiredFlags => write!(f, "Missing required flags for POSIX thread"),
            Self::ConflictWithNewNamespace => {
                write!(f, "CLONE_NEWNS cannot be used with shared VM")
            }
        }
    }
}

impl CloneFlags {
    /// 验证标志是否符合 POSIX 线程要求
    pub fn validate_pthread(&self) -> Result<(), CloneFlagError> {
        // 检查必须的标志
        let required = CloneFlags::SHARE_VM
            | CloneFlags::SHARE_FILES
            | CloneFlags::SHARE_SIGHANDLER
            | CloneFlags::THREAD_GROUP;

        if !self.contains(required) {
            return Err(CloneFlagError::MissingRequiredFlags);
        }

        // 检查冲突标志
        if self.contains(CloneFlags::NEW_NET_NS) {
            return Err(CloneFlagError::ConflictWithNewNamespace);
        }

        Ok(())
    }
}

