impl FdTable {
    pub fn new(inner: FdTableInner) -> Self {
        Self {
            inner: unsafe { UPSafeCell::new(inner) },
        }
    }
    pub fn new_with_stdio() -> Self {
        let mut files = Vec::new();
        files.push(Some(FileDescriptor::default(FileClass::Abs(Arc::new(
            Stdin,
        )))));
        files.push(Some(FileDescriptor::default(FileClass::Abs(Arc::new(
            Stdout,
        )))));
        files.push(Some(FileDescriptor::default(FileClass::Abs(Arc::new(
            Stdout,
        )))));
        Self {
            inner: unsafe { UPSafeCell::new(FdTableInner::new(files)) },
        }
    }
    pub fn from_existed_user(parent: Arc<FdTable>) -> Self {
        let inner = parent.inner_exclusive_access();
        Self::new(FdTableInner::new_with_limit(
            inner.soft_limit,
            inner.hard_limit,
            inner.files.clone(),
        ))
    }
    pub fn inner_exclusive_access(&self) -> RefMut<'_, FdTableInner> {
        self.inner.exclusive_access()
    }
    pub fn clear(&self) {
        let mut inner = self.inner_exclusive_access();
        inner.files.clear();
        inner.soft_limit = 64;
        inner.hard_limit = 256;
    }
    pub fn alloc_fd(&self) -> usize {
        let mut inner = self.inner_exclusive_access();
        let soft_limit = inner.soft_limit;
        let mut files = &mut inner.files;

        if let Some(fd) = (0..files.len()).find(|fd| files[*fd].is_none()) {
            info!("Reusing fd: {}", fd);
            return fd;
        }
        if files.len() >= soft_limit {
            // 已达到软限制，无法分配新的文件描述符
            return usize::MAX; // 使用特殊值表示失败
        }
        files.push(None);
        files.len() - 1
    }
    pub fn alloc_fd_larger(&self, arg: usize) -> SyscallRet {
        let mut inner = self.inner_exclusive_access();
        let soft_limit = inner.soft_limit;
        let mut files = &mut inner.files;
        if arg >= soft_limit {
            return Err(SysErrNo::EMFILE);
        }
        if files.len() < arg {
            files.resize(arg, None);
        }

        if let Some(fd) = (arg..files.len()).find(|fd| files[*fd].is_none()) {
            Ok(fd)
        } else if files.len() >= soft_limit {
            Err(SysErrNo::EMFILE)
        } else {
            files.push(None);
            Ok(files.len() - 1)
        }
    }
    pub fn remove(&self, fd: usize) -> Option<FileDescriptor> {
        let mut inner = self.inner_exclusive_access();
        if fd >= inner.files.len() {
            return None;
        }
        inner.files[fd].take()
    }
    pub fn len(&self) -> usize {
        self.inner_exclusive_access().files.len()
    }
    pub fn get_file(&self, fd: usize) -> Option<FileDescriptor> {
        let inner = self.inner_exclusive_access();
        if fd >= inner.files.len() {
            return None;
        }
        inner.files[fd].clone()
    }
    pub fn resize(&self, new_size: usize) {
        let mut inner = self.inner_exclusive_access();
        if new_size < inner.files.len() {
            inner.files.truncate(new_size);
        } else {
            inner.files.resize(new_size, None);
        }
    }

    pub fn close_on_exec(&self) {
        let mut inner = self.inner_exclusive_access();
        for file in &mut inner.files {
            if let Some(ref fd) = file {
                if fd.cloexec() {
                    *file = None; // 关闭时清除文件描述符
                }
            }
        }
    }
    pub fn set_cloexec(&self, fd: usize) {
        let mut inner = self.inner_exclusive_access();
        if fd < inner.files.len() {
            if let Some(ref mut f) = inner.files[fd] {
                f.set_cloexec();
            }
        }
    }

    pub fn unset_cloexec(&self, fd: usize) {
        let mut inner = self.inner_exclusive_access();
        if fd < inner.files.len() {
            if let Some(ref mut f) = inner.files[fd] {
                f.unset_cloexec();
            }
        }
    }

    pub fn set_nonblock(&self, fd: usize) {
        let mut inner = self.inner_exclusive_access();
        if fd < inner.files.len() {
            if let Some(ref mut f) = inner.files[fd] {
                f.set_nonblock();
            }
        }
    }

    pub fn unset_nonblock(&self, fd: usize) {
        let mut inner = self.inner_exclusive_access();
        if fd < inner.files.len() {
            if let Some(ref mut f) = inner.files[fd] {
                f.unset_nonblock();
            }
        }
    }

    pub fn get_hard_limit(&self) -> usize {
        self.inner_exclusive_access().hard_limit
    }

    pub fn get_soft_limit(&self) -> usize {
        self.inner_exclusive_access().soft_limit
    }

    pub fn set_limit(&self, soft_limit: usize, hard_limit: usize) {
        let mut inner = self.inner_exclusive_access();
        inner.soft_limit = soft_limit;
        inner.hard_limit = hard_limit;
    }

    pub fn set(&self, fd: usize, file: FileDescriptor) {
        let mut inner = self.inner_exclusive_access();
        if fd >= inner.files.len() {
            if fd < inner.hard_limit {
                inner.files.resize(fd + 1, None);
            } else {
                return; // fd 超出硬限制，静默忽略
            }
        }
        inner.files[fd] = Some(file);
    }

    pub fn take(&self, fd: usize) -> Option<FileDescriptor> {
        let mut inner = self.inner_exclusive_access();
        if fd >= inner.files.len() {
            return None;
        }
        inner.files[fd].take()
    }
}

