fn fork_mapped_vaddrs(area: &MapArea) -> Vec<VirtAddr> {
    let (start, end) = area.vaddr_range.range();
    let page_count = (end.raw() - start.raw()) / PAGE_SIZE;
    let frame_count = area.data_frames.len();
    let scan_limit = frame_count.saturating_mul(4).saturating_add(16);

    if page_count <= scan_limit {
        area.vaddr_range
            .into_iter()
            .filter(|vaddr| area.data_frames.get(vaddr).is_some())
            .collect()
    } else {
        area.data_frames.keys().cloned().collect()
    }
}

