impl VirtIOBlock {
    #[allow(unused)]
    pub fn new() -> Self {
        trace!("VirtIOBlock::new()");
        #[cfg(target_arch = "riscv64")]
        unsafe {
            let virtio_header_addr = (VIRTIO0 | VIRT_ADDR_START) as *mut VirtIOHeader;
            let virtio_header_ptr = NonNull::new_unchecked(virtio_header_addr);
            let mmio_transport =
                MmioTransport::new(virtio_header_ptr).expect("this is not a valid virtio device");
            let virtio_transport = VirtioTransportImpl::Mmio(mmio_transport);
            let virtio_blk =
                VirtIOBlk::<VirtioHal, VirtioTransportImpl>::new(virtio_transport).unwrap();
            Self(UPSafeCell::new(virtio_blk))
        }
        #[cfg(target_arch = "loongarch64")]
        unsafe {
            use virtio_drivers::transport::pci::virtio_device_type;
            use virtio_drivers::transport::DeviceType;
            let mmconfig_base = (0x2000_0000usize | VIRT_ADDR_START) as *mut u8;
            let mut pci_root = PciRoot::<MmioCam>::new(MmioCam::new(
                mmconfig_base,
                virtio_drivers::transport::pci::bus::Cam::Ecam,
            ));

            // 简单遍历bus 0，找到第一个 virtio block 设备
            let mut found = None;
            for (device_function, info) in pci_root.enumerate_bus(0) {
                if let Some(virtio_type) = virtio_device_type(&info) {
                    if virtio_type == DeviceType::Block {
                        found = Some(device_function);
                        break;
                    }
                }
            }
            let device_function = found.expect("No virtio block device found on PCI bus");

            // 启用设备的BAR
            pci_root.set_command(
                device_function,
                virtio_drivers::transport::pci::bus::Command::IO_SPACE
                    | virtio_drivers::transport::pci::bus::Command::MEMORY_SPACE
                    | virtio_drivers::transport::pci::bus::Command::BUS_MASTER,
            );
            Self::dump_bar_contents(&mut pci_root, device_function, 4);
            let pci_transport =
                PciTransport::new::<VirtioHal, MmioCam>(&mut pci_root, device_function)
                    .expect("Failed to create PCI transport");
            let virtio_transport = VirtioTransportImpl::Pci(pci_transport);
            trace!("VirtIOBlock::new() - PCI transport created:");
            let virtio_blk =
                VirtIOBlk::<VirtioHal, VirtioTransportImpl>::new(virtio_transport).unwrap();
            Self(UPSafeCell::new(virtio_blk))
        }
    }
}

#[cfg(target_arch = "loongarch64")]
impl VirtIOBlock {
    fn dump_bar_contents(
        root: &mut PciRoot<MmioCam>,
        device_function: DeviceFunction,
        bar_index: u8,
    ) {
        use virtio_drivers::transport::pci::bus::{BarInfo, MemoryBarType};

        lazy_static! {
            static ref PCI_RANGES: UPSafeCell<(usize, usize)> =
                unsafe { UPSafeCell::new((0x4000_0000, 0x2_0000)) };
        }

        let bar_info = root.bar_info(device_function, bar_index).unwrap();
        trace!("Dumping bar {}: {:#x?}", bar_index, bar_info);

        if let BarInfo::Memory {
            address,
            size,
            address_type,
            ..
        } = bar_info
        {
            if address == 0 && size > 0 {
                let mut ranges = PCI_RANGES.exclusive_access();
                assert!(ranges.1 > size as usize);
                let start = ranges.0;
                ranges.1 -= size as usize;
                ranges.0 += size as usize;
                drop(ranges);

                match address_type {
                    MemoryBarType::Width32 => {
                        root.set_bar_32(device_function, bar_index, start as _)
                    }
                    MemoryBarType::Below1MiB => todo!(),
                    MemoryBarType::Width64 => {
                        root.set_bar_64(device_function, bar_index, start as _)
                    }
                }
            }
        }
    }
}

