    }
}

pub fn unregister_device(abs_path: &str) {
    DEVICES.lock().devices.remove(abs_path);
}

pub fn find_device(abs_path: &str) -> bool {
    DEVICES.lock().devices.get(abs_path).is_some()
}

pub fn get_devno(abs_path: &str) -> usize {
    *DEVICES.lock().devices.get(abs_path).unwrap()
}

pub fn open_device_file(abs_path: &str) -> Result<Arc<dyn File>, SysErrNo> {
    match abs_path {
        "/dev/zero" => Ok(Arc::new(DevZero::new())),
        "/dev/null" => Ok(Arc::new(DevNull::new())),
        "/dev/rtc" => Ok(Arc::new(DevRtc::new("/dev/rtc"))),
        "/dev/rtc0" => Ok(Arc::new(DevRtc::new("/dev/rtc0"))),
        "/dev/misc/rtc" => Ok(Arc::new(DevRtc::new("/dev/misc/rtc"))),
        "/dev/random" => Ok(Arc::new(DevRandom::new("/dev/random"))),
        "/dev/urandom" => Ok(Arc::new(DevRandom::new("/dev/urandom"))),
        "/dev/tty" => Ok(Arc::new(DevTty::new())),
        "/dev/cpu_dma_latency" => Ok(Arc::new(DevCpuDmaLatency::new())),
        _ => Err(SysErrNo::ENOENT),
    }
}

