pub struct VirtFile {
    path: &'static str,
    offset: Mutex<usize>,
}
impl VirtFile {
    pub fn new(path: &'static str) -> Self {
        Self {
            path,
            offset: Mutex::new(0),
        }
    }
}

impl File for VirtFile {
    fn readable(&self) -> bool {
        true
    }
    fn writable(&self) -> bool {
        false
    }
    fn read(&self, mut buf: UserBuffer) -> usize {
        trace!("[VirtFile::read] called");
        // 直接调用 IRQ 统计模块
        let counts = get_irq_counts();
        let mut result = String::new();
        debug!("[VirtFile::read] IRQ counts: {:?}", counts);
        for (irq, &count) in counts.iter().enumerate() {
            if count > 0 {
                use core::fmt::Write;
                // 修复格式：在IRQ号前添加空格，符合Linux /proc/interrupts的格式
                let _ = write!(result, " {}: {}\n", irq, count);
            }
        }
        let content_bytes = result.as_bytes();
        let mut offset = self.offset.lock();
        let start = *offset;
        // debug!(
        //     "[VirtFile::read] start: {}, content length: {}",
        //     start,
        //     content_bytes.len()
        // );
        if start >= content_bytes.len() {
            debug!("[VirtFile::read] start is beyond content length, returning 0");
            return 0;
        }
        let end = min(start + buf.len(), content_bytes.len());
        let len = end - start;
        let written = &content_bytes[start..end];
        buf.write(written);
        debug!(
            "[VirtFile::read] return: {}",
            core::str::from_utf8(written).unwrap_or("<invalid utf8>")
        );
        *offset = end;
        len
    }

    fn write(&self, _buf: UserBuffer) -> usize {
        0
    }

    fn fstat(&self) -> Kstat {
        Kstat {
            st_mode: StMode::FREG.bits(), // 管道文件类型
            st_nlink: 1,                  // 管道有一个链接
            ..Kstat::default()
        }
    }

    fn get_name(&self) -> String {
        self.path.to_string()
    }

    fn set_offset(&self, offset: usize) {
        *self.offset.lock() = offset;
    }

    fn get_dirent(&self, dirent: &mut super::Dirent) -> isize {
        -1
    }

    fn poll(&self, events: PollEvents) -> PollEvents {
        //todo!()
        PollEvents::empty()
    }
}
/// 虚拟文件注册表，路径 -> 虚拟文件对象
lazy_static! {
    pub static ref VFS_REGISTRY: RwLock<BTreeMap<&'static str, Arc<dyn File>>> =
        RwLock::new(BTreeMap::new());
}

/// 注册一个虚拟文件
pub fn register_vfile(path: &'static str, file: Arc<dyn File>) {
    VFS_REGISTRY.write().insert(path, file);
}

/// 查询虚拟文件
pub fn get_vfile(path: &str) -> Option<Arc<dyn File>> {
    VFS_REGISTRY.read().get(path).cloned()
}

/// 静态只读虚拟文件：内容固定，每个 open 维护独立 offset。
/// 用于 /proc/self/maps 这类 LTP 只关心能 open/read 的占位文件。
pub struct StaticVirtFile {
    path: &'static str,
    content: &'static str,
    offset: Mutex<usize>,
}

impl StaticVirtFile {
    pub fn new(path: &'static str, content: &'static str) -> Self {
        Self {
            path,
            content,
            offset: Mutex::new(0),
        }
    }
}

impl File for StaticVirtFile {
    fn readable(&self) -> bool {
        true
    }
    fn writable(&self) -> bool {
        false
    }
    fn read(&self, mut buf: UserBuffer) -> usize {
        let bytes = self.content.as_bytes();
        let mut offset = self.offset.lock();
        let start = *offset;
        if start >= bytes.len() {
            return 0;
        }
        let end = min(start + buf.len(), bytes.len());
        let len = end - start;
        buf.write(&bytes[start..end]);
        *offset = end;
        len
    }
    fn write(&self, _buf: UserBuffer) -> usize {
        0
    }
    fn fstat(&self) -> Kstat {
        Kstat {
            st_mode: StMode::FREG.bits(),
            st_nlink: 1,
            st_size: self.content.len() as isize,
            ..Kstat::default()
        }
    }
    fn get_name(&self) -> String {
        self.path.to_string()
    }
    fn set_offset(&self, offset: usize) {
        *self.offset.lock() = offset;
    }
    fn get_dirent(&self, _dirent: &mut super::Dirent) -> isize {
        -1
    }
    fn poll(&self, events: PollEvents) -> PollEvents {
        let mut revents = PollEvents::empty();
        if events.contains(PollEvents::POLLIN) {
            revents |= PollEvents::POLLIN;
        }
        revents
    }
}

fn parse_proc_pid_leaf(path: &str, leaf: &str) -> Option<usize> {
    let rest = path.strip_prefix("/proc/")?;
    let leaf_suffix = {
        let mut suffix = String::from("/");
        suffix.push_str(leaf);
        suffix
    };
    if !rest.ends_with(leaf_suffix.as_str()) {
        return None;
    }
    let pid_part = &rest[..rest.len() - leaf_suffix.len()];
    if pid_part.is_empty() || pid_part.as_bytes().iter().any(|b| !b.is_ascii_digit()) {
        return None;
    }
    pid_part.parse::<usize>().ok()
}

pub fn get_dynamic_vfile(path: &str) -> Option<Arc<dyn File>> {
    if let Some(pid) = parse_proc_pid_leaf(path, "stat") {
        if pid2task(pid).is_some() {
            return Some(Arc::new(ProcPidFile::new_stat(path, pid)));
        }
    }
    if let Some(pid) = parse_proc_pid_leaf(path, "status") {
        if pid2task(pid).is_some() {
            return Some(Arc::new(ProcPidFile::new_status(path, pid)));
        }
    }
    None
}

