const LF: u8 = 0x0a;
const CR: u8 = 0x0d;

pub struct Stdin;

pub struct Stdout;

impl File for Stdin {
    fn readable(&self) -> bool {
        true
    }
    fn writable(&self) -> bool {
        false
    }
    fn read(&self, mut user_buf: UserBuffer) -> usize {
        if user_buf.len() == 1 {
            // 单字符读取模式（无回显，立即返回）
            let c = loop {
                if let Some(ch) = DebugConsole::getchar() {
                    break ch;
                }
                suspend_current_and_run_next();
            };

            let input_data = [c];
            user_buf.write(&input_data)
        } else {
            // 行缓冲读取模式（有回显，等待换行）
            let mut count: usize = 0;
            let mut input_buf = Vec::new();

            while count < user_buf.len() {
                // 获取字符
                let c = loop {
                    if let Some(ch) = DebugConsole::getchar() {
                        break ch;
                    }
                    suspend_current_and_run_next();
                };

                // 处理特殊字符
                match c {
                    // 回车转换为换行
                    CR => {
                        print!("\n");
                        input_buf.push(LF);
                        count += 1;
                        break; // 遇到回车就结束输入
                    }
                    // 换行符直接使用
                    LF => {
                        print!("\n");
                        input_buf.push(LF);
                        count += 1;
                        break; // 遇到换行就结束输入
                    }
                    // 普通字符，直接回显并写入
                    _ => {
                        print!("{}", c as char);
                        input_buf.push(c);
                        count += 1;
                    }
                }
            }
            // 使用 UserBuffer 的 write 方法一次性写入
            user_buf.write(&input_buf)
        }
    }

    fn write(&self, _user_buf: UserBuffer) -> usize {
        panic!("Cannot write to stdin!");
    }

    fn fstat(&self) -> Kstat {
        Kstat {
            st_mode: StMode::FCHR.bits(), // 文件类型
            st_nlink: 1,                  // 有一个链接
            ..Kstat::default()
        }
    }

    #[allow(unused_variables)]
    fn get_dirent(&self, dirent: &mut Dirent) -> isize {
        panic!("Stdin not implement get_dirent");
    }

    fn get_name(&self) -> String {
        panic!("Stdin not implement get_name");
    }

    fn set_offset(&self, offset: usize) {
        panic!("Stdin not implement set_offset");
    }

    fn poll(&self, events: PollEvents) -> PollEvents {
        let mut revents = PollEvents::empty();
        if events.contains(PollEvents::POLLIN) {
            revents |= PollEvents::POLLIN;
        }
        revents
    }
}

impl File for Stdout {
    fn readable(&self) -> bool {
        false
    }
    fn writable(&self) -> bool {
        true
    }
    fn read(&self, _user_buf: UserBuffer) -> usize {
        panic!("Cannot read from stdout!");
    }
    fn write(&self, user_buf: UserBuffer) -> usize {
        for buffer in user_buf.buffers.iter() {
            match core::str::from_utf8(*buffer) {
                Ok(s) => print!("{}", s),
                Err(_) => {
                    for byte in buffer.iter() {
                        print!("{}", char::from(*byte));
                    }
                }
            }
        }
        user_buf.len()
    }
