fn timespec_to_ms(ts: Timespec) -> Result<usize, SysErrNo> {
    if ts.tv_nsec >= 1_000_000_000 {
        return Err(SysErrNo::EINVAL);
    }
    let sec_ms = ts.tv_sec.checked_mul(1000).ok_or(SysErrNo::EINVAL)?;
    let nsec_ms = (ts.tv_nsec + 999_999) / 1_000_000;
    sec_ms.checked_add(nsec_ms).ok_or(SysErrNo::EINVAL)
}

