pub fn sys_sig_kill(pid: isize, sig: u32) -> SyscallRet {
    trace!("[sys_sig_kill] Enter: pid={}, sig={}", pid, sig);
    if sig as usize > MAX_SIG {
        return Err(SysErrNo::EINVAL);
    }
    let signal = if sig == 0 {
        None
    } else {
        Some(SignalFlags::from_bits(1u64 << sig).ok_or(SysErrNo::EINVAL)?)
    };

    if pid > 0 {
        // Send to specific process
        if let Some(task) = pid2task(pid as usize) {
            if let Some(signal) = signal {
                task.inner_exclusive_access().signals |= signal;
            }
            Ok(0)
        } else {
            Err(SysErrNo::ESRCH)
        }
    } else if pid == 0 {
        // Send to all processes in the current process group
        let pgid = {
            let current = current_task().unwrap();
            let inner = current.inner_exclusive_access();
            inner.pgid
        };
        if send_signal_to_pgid(pgid, signal) == 0 {
            Err(SysErrNo::ESRCH)
        } else {
            Ok(0)
        }
    } else if pid == -1 {
        // Send to all processes (except init)
        let current = current_task().unwrap();
        let current_pid = current.getpid();
        if send_signal_to_all(signal, current_pid) == 0 {
            Err(SysErrNo::ESRCH)
        } else {
            Ok(0)
        }
    } else {
        // pid < -1: send to process group (-pid)
        let pgid = (-pid) as usize;
        if send_signal_to_pgid(pgid, signal) == 0 {
            Err(SysErrNo::ESRCH)
        } else {
            Ok(0)
        }
    }
}

/// Send a signal to all processes in a process group
fn send_signal_to_pgid(pgid: usize, signal: Option<SignalFlags>) -> usize {
    let tasks = crate::task::get_all_tasks();
    let init_pid = crate::task::INITPROC.getpid();
    let mut delivered = 0;
    for (pid, task) in tasks.iter() {
        if *pid == init_pid && signal.is_some() {
            continue;
        }
        let matches_group = {
            let inner = task.inner_exclusive_access();
            inner.pgid == pgid
        };
        if matches_group {
            if let Some(signal) = signal {
                let mut inner = task.inner_exclusive_access();
                inner.signals |= signal;
            }
            delivered += 1;
        }
    }
    delivered
}

/// Send a signal to all processes (except the given pid)
fn send_signal_to_all(signal: Option<SignalFlags>, except_pid: usize) -> usize {
    let tasks = crate::task::get_all_tasks();
    let mut delivered = 0;
    for (pid, task) in tasks.iter() {
        if *pid != except_pid && *pid != 1 {
            if let Some(signal) = signal {
                task.inner_exclusive_access().signals |= signal;
            }
            delivered += 1;
        }
    }
    delivered
}

// tgkill(tgid, tid, sig) targets a specific thread. This kernel approximates a
// thread group as tasks sharing the same address space or signal action table.
pub fn sys_tgkill(tgid: usize, tid: usize, sig: u32) -> SyscallRet {
    trace!(
        "[sys_tgkill] Enter: tgid={}, tid={}, sig={}",
        tgid,
        tid,
        sig
    );
    if sig as usize > MAX_SIG {
        return Err(SysErrNo::EINVAL);
    }
    let task = pid2task(tid).ok_or(SysErrNo::ESRCH)?;
    if tgid != tid {
        let leader = pid2task(tgid).ok_or(SysErrNo::ESRCH)?;
        let same_thread_group = {
            let task_inner = task.inner_exclusive_access();
            let leader_inner = leader.inner_exclusive_access();
            Arc::ptr_eq(&task_inner.memory_set, &leader_inner.memory_set)
                || Arc::ptr_eq(&task_inner.sig_table, &leader_inner.sig_table)
        };
        if !same_thread_group {
            return Err(SysErrNo::ESRCH);
        }
    }
    if sig != 0 {
        let signal = SignalFlags::from_bits(1u64 << sig).ok_or(SysErrNo::EINVAL)?;
        task.inner_exclusive_access().signals |= signal;
    }
    Ok(0)
}

