unsafe fn str_len(ptr: *const u8) -> usize {
    let mut i = 0;
    loop {
        if *ptr.add(i) == 0 {
            break i;
        }
        i += 1;
    }
}

pub fn translated_byte_buffer(
    token: &PageTable,
    ptr: *mut u8,
    len: usize,
) -> Vec<&'static mut [u8]> {
    // trace!("translated_byte_buffer");
    if len == 0 {
        return Vec::new();
    }
    let buffer = unsafe { core::slice::from_raw_parts_mut(ptr, len) };
    vec![buffer]
}

pub fn translated_str(token: PageTable, ptr: *const u8) -> String {
    unsafe {
        let len = str_len(ptr);
        // println!("ptr:{:#x}", ptr as usize);
        from_utf8_unchecked(slice::from_raw_parts(ptr, len)).to_string()
    }
}

/// Fallible version of `translated_str`: validates each byte of the user
/// pointer before dereferencing, returning `EFAULT` instead of faulting in
/// kernel mode when the pointer is invalid (e.g. `(void *)-1`).
pub fn try_translated_str(token: PageTable, ptr: *const u8) -> Result<String, SysErrNo> {
    if ptr.is_null() {
        return Err(SysErrNo::EFAULT);
    }
    let base = ptr as usize;
    let mut len = 0usize;
    loop {
        if len >= 4096 * 4 {
            return Err(SysErrNo::EFAULT);
        }
        let addr = base.checked_add(len).ok_or(SysErrNo::EFAULT)?;
        if addr >= VIRT_ADDR_START {
            return Err(SysErrNo::EFAULT);
        }
        if token.translate(VirtAddr::new(addr)).is_none() {
            return Err(SysErrNo::EFAULT);
        }
        if unsafe { *(addr as *const u8) } == 0 {
            break;
        }
        len += 1;
    }
    let s = unsafe { from_utf8_unchecked(slice::from_raw_parts(ptr, len)) };
    Ok(s.to_string())
}

pub fn translated_ref<T>(token: PageTable, ptr: *const T) -> &'static T {
    unsafe { ptr.as_ref().unwrap() }
}

pub fn translated_refmut<T>(token: PageTable, ptr: *mut T) -> &'static mut T {
    unsafe { ptr.as_mut().unwrap() }
}

