///Array of u8 slice that user communicate with os
pub struct UserBuffer {
    ///U8 vec
    pub buffers: Vec<&'static mut [u8]>,
}

impl UserBuffer {
    ///Create a `UserBuffer` by parameter
    pub fn new(buffers: Vec<&'static mut [u8]>) -> Self {
        Self { buffers }
    }
    ///Length of `UserBuffer`
    pub fn len(&self) -> usize {
        let mut total: usize = 0;
        for b in self.buffers.iter() {
            total += b.len();
        }
        total
    }

    /// 将一个缓冲区的数据写入用户缓冲区，返回实际写入的字节数。
    pub fn write(&mut self, buff: &[u8]) -> usize {
        let len = self.len().min(buff.len()); // 确定要写入的总长度
        if len == 0 {
            return 0;
        }
        let mut current = 0; // 当前已写入的字节数

        // 遍历每个子缓冲区并填充数据
        for sub_buff in self.buffers.iter_mut() {
            let sblen = sub_buff.len(); // 当前子缓冲区的长度
            for j in 0..sblen {
                sub_buff[j] = buff[current]; // 将数据写入子缓冲区
                current += 1; // 增加已写入计数

                if current == len {
                    // 如果已写入指定长度，提前返回
                    return len;
                }
            }
        }

        len // 返回实际写入的总长度
    }
}

impl IntoIterator for UserBuffer {
    type Item = *mut u8;
    type IntoIter = UserBufferIterator;
    fn into_iter(self) -> Self::IntoIter {
        UserBufferIterator {
            buffers: self.buffers,
            current_buffer: 0,
            current_idx: 0,
        }
    }
}
/// Iterator of `UserBuffer`
pub struct UserBufferIterator {
    buffers: Vec<&'static mut [u8]>,
    current_buffer: usize,
    current_idx: usize,
}

impl Iterator for UserBufferIterator {
    type Item = *mut u8;
    fn next(&mut self) -> Option<Self::Item> {
        while self.current_buffer < self.buffers.len()
            && self.current_idx >= self.buffers[self.current_buffer].len()
        {
            self.current_idx = 0;
            self.current_buffer += 1;
        }
        if self.current_buffer >= self.buffers.len() {
            return None;
        }
        let r = &mut self.buffers[self.current_buffer][self.current_idx] as *mut _;
        self.current_idx += 1;
        Some(r)
    }
}

use lazy_static::lazy_static;
