/// 假设支持的中断号数量
pub const MAX_IRQ: usize = 64;

lazy_static! {
    /// 全局中断计数器
    static ref IRQ_COUNTS: Mutex<[usize; MAX_IRQ]> = Mutex::new([0; MAX_IRQ]);
}

/// 在发生中断时调用，增加对应中断号的计数
pub fn inc_irq_count(irq: usize) {
    if irq < MAX_IRQ {
        // warn!("Incrementing IRQ count for IRQ: {}", irq);
        let mut counts = IRQ_COUNTS.lock();
        counts[irq] = counts[irq].saturating_add(1);
    }
}

/// 获取所有中断计数的快照
pub fn get_irq_counts() -> [usize; MAX_IRQ] {
    let counts = IRQ_COUNTS.lock();
    *counts
}

