pub const NAME_LIMIT: usize = 256;

/// 存储目录中的文件信息
#[repr(C)]
pub struct Dirent {
    pub d_ino: usize,             // 索引节点号
    pub d_off: isize,             // 从 0 开始到下一个 dirent 的偏移
    pub d_reclen: u16,            // 当前 dirent 的长度
    pub d_type: u8,               // 文件类型
    pub d_name: [u8; NAME_LIMIT], // 文件名
}

impl Dirent {
    pub fn new(mut name: String, off: i64, ino: u64, dtype: u8) -> Self {
        //对齐 align8
        name += "\0";
        let mut len = name.len() + 19;
        let align = 8 - len % 8;
        len += align;
        for _ in 0..align {
            name.push('\0');
        }
        Self {
            d_ino: ino as usize,
            d_off: off as isize,
            d_reclen: len as u16,
            d_type: dtype,
            d_name: {
                let mut tmp: [u8; 256] = [0; 256];
                tmp[..name.len()].copy_from_slice(name.as_bytes());
                tmp
            },
        }
    }

    pub fn init(&mut self, name: &str) {
        self.fill_name(name);
    }

    fn fill_name(&mut self, name: &str) {
        let len = name.len().min(NAME_LIMIT);
        let name_bytes = name.as_bytes();
        for i in 0..len {
            self.d_name[i] = name_bytes[i];
        }
        self.d_name[len] = 0;
    }

    pub fn as_bytes(&self) -> &[u8] {
        unsafe { core::slice::from_raw_parts(self as *const _ as usize as *const u8, self.len()) }
    }
    #[inline(always)]
    pub fn len(&self) -> usize {
        self.d_reclen as usize
    }
    #[inline(always)]
    pub fn off(&self) -> isize {
        self.d_off as isize
    }
}

