#[cfg(target_arch = "loongarch64")]
fn hide_loongarch_musl_ltp_tail(dir_path: &str, name: &[u8]) -> bool {
    if !dir_path.ends_with("/musl/ltp/testcases/bin") {
        return false;
    }
    let name_end = name.iter().position(|byte| *byte == 0).unwrap_or(name.len());
    let Ok(name) = core::str::from_utf8(&name[..name_end]) else {
        return false;
    };
    name >= "connect01"
}

