impl Ext4Inode {
    pub fn new(path: &str, types: InodeTypes) -> Self {
        Ext4Inode {
            inner: unsafe {
                UPSafeCell::new(Ext4InodeInner {
                    f: Ext4File::new(path, types),
                    delay: false,
                })
            },
        }
    }
    // pub fn lwext4_dir_entries(&self) -> Result<(Vec<Vec<u8>>, Vec<InodeTypes>), i32> {
    //     let file = &mut self.inner.exclusive_access().f;
    //     file.lwext4_dir_entries()
    // }
}

impl Ext4Inode {
    pub fn size(&self) -> usize {
        let file = &mut self.inner.exclusive_access().f;
        let types = as_inode_type(file.types());
        if types == InodeType::File {
            let path = file.path();
            let path = path.to_str().unwrap();
            file.file_open(path, O_RDONLY);
            let fsize = file.file_size();
            let _ = file.file_close();
            fsize as usize
        } else {
            0
        }
    }
    /// Ext4Inode创建必须使用绝对路径
    pub fn create(&self, path: &str, ty: InodeType) -> Result<Arc<Ext4Inode>, SysErrNo> {
        let types = as_ext4_de_type(ty);
        let file = &mut self.inner.exclusive_access().f;
        let nf = Ext4Inode::new(path, types.clone());

        if !file.check_inode_exist(path, types.clone()) {
            let nfile = &mut nf.inner.exclusive_access().f;
            if types == InodeTypes::EXT4_DE_DIR {
                if let Err(e) = nfile.dir_mk(path) {
                    return Err(SysErrNo::from(e));
                }
            } else if let Err(e) = nfile.file_open(path, O_RDWR | O_CREAT | O_TRUNC) {
                return Err(SysErrNo::from(e));
            } else {
                nfile.file_close()?;
            }
        }
        Ok(Arc::new(nf))
    }

    pub fn types(&self) -> InodeType {
        as_inode_type(self.inner.exclusive_access().f.types())
    }

    pub fn read_at(&self, off: usize, buf: &mut [u8]) -> SyscallRet {
        let file = &mut self.inner.exclusive_access().f;
        let path = file.path();
